export const SvgIconSize = {
    Micro: "micro",
    Tiny: "tiny",
    Small: "small",
    Big: "big",
    Bigger: "bigger",
    Large: "large",
    Huge: "huge",
    Huger: "huger"
};
export const driveIconSize = (value) => {
    const orderedSizes = [
        SvgIconSize.Micro,
        SvgIconSize.Tiny,
        SvgIconSize.Small,
        SvgIconSize.Big,
        SvgIconSize.Bigger,
        SvgIconSize.Large,
        SvgIconSize.Huge,
        SvgIconSize.Huger
    ];
    const index = orderedSizes.indexOf(value);
    if (index !== -1 && index < orderedSizes.length - 1) {
        return orderedSizes[index + 1];
    }
    return value;
};
