const camelToKebab = (str) => str.replace(/[A-Z]/g, letter => `-${letter.toLowerCase()}`);
export const getAriaAttributes = (props) => {
    if (!props) {
        return {};
    }
    const ariaAttributes = {};
    for (const [key, value] of Object.entries(props)) {
        // Handle hyphenated aria attributes (aria-*)
        if (key.startsWith("aria-")) {
            ariaAttributes[key] = value;
        }
        // Handle camelCase aria attributes (ariaDescribedby, ariaLabel, etc.)
        // Convert to hyphenated format (aria-describedby, aria-label, etc.)
        else if (key.startsWith("aria") && key.length > 4 && key[4] === key[4].toUpperCase()) {
            const hyphenated = camelToKebab(key);
            ariaAttributes[hyphenated] = value;
        }
    }
    return ariaAttributes;
};
